using System.Net.Http; namespace Arq.Lab.Library.Http; public static class HttpClientPolicy { private static readonly Func<HttpClientHandler, HttpClientHandler> Binder = handler => { handler.ServerCertificateCustomValidationCallback = HttpClientHandler.DangerousAcceptAnyServerCertificateValidator; return handler; }; public static HttpClientHandler Build() => Binder(new HttpClientHandler()); }
